// Parse pipeline stdout to extract summary stats
const output = $input.first().json.stdout || '';

const approved = (output.match(/APPROVED:\s*(\d+)/) || [])[1] || '0';
const denied = (output.match(/DENIED:\s*(\d+)/) || [])[1] || '0';
const appeal = (output.match(/APPEAL:\s*(\d+)/) || [])[1] || '0';
const pending = (output.match(/PENDING:\s*(\d+)/) || [])[1] || '0';
const errors = (output.match(/ERRORS:\s*(\d+)/) || [])[1] || '0';

const total = parseInt(approved) + parseInt(denied) + parseInt(appeal) + parseInt(pending) + parseInt(errors);

return [{
  json: {
    approved: parseInt(approved),
    denied: parseInt(denied),
    appeal: parseInt(appeal),
    pending: parseInt(pending),
    errors: parseInt(errors),
    total,
    runDate: new Date().toISOString().split('T')[0],
    summaryLine: `${approved} Approved | ${denied} Denied | ${appeal} Appeal | ${pending} Pending | ${errors} Errors`
  }
}];

